#!/usr/bin/env node
/**
 * One-shot migration: products.json (191 entries, canonical) → lib/catalogue-data.ts.
 *
 * Run from the project root:
 *     node scripts/migrate-catalogue.mjs
 *
 * Output: lib/catalogue-data.ts overwritten with the full 191-product PRODUCTS array.
 *
 * Why this script lives in the repo: products.json may be regenerated by the
 * data team (re-export from WordPress, manual edits to specs, new products).
 * Re-running this script is the supported path to refresh the TypeScript fixture
 * — do NOT hand-edit lib/catalogue-data.ts after running it.
 *
 * Mapping rules are documented in CLAUDE_CODE_MIGRATION_PROMPT.md. This file
 * is the executable version of those rules — when in doubt, the prompt's rules
 * are the spec; this script is the implementation.
 */

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const PROJECT_ROOT = path.resolve(__dirname, "..");
const PRODUCTS_JSON = path.join(PROJECT_ROOT, "products.json");
const OVERRIDES_JSON = path.join(PROJECT_ROOT, "data", "category_overrides.json");
const OUTPUT_PATH = path.join(PROJECT_ROOT, "lib", "catalogue-data.ts");

const VALID_CERTIFICATIONS = new Set([
  "WaterMark",
  "WELS",
  "NSF",
  "AS/NZS 4020",
  "AS/NZS 3497",
]);

// Human-readable names for each category slug — used to build the
// `categoryPath` breadcrumb on each Product record.
const CATEGORY_TITLES = {
  // Top-level (3-tier structure)
  "water-filters": "Water Filters",
  "bubblers-and-coolers": "Bubblers & Coolers",
  more: "Bathroom, Kitchen & Specialty",

  // water-filters/
  "whole-house": "Whole House",
  "under-sink": "Under Sink",
  "reverse-osmosis": "Reverse Osmosis",
  "bench-top": "Bench Top",
  "uv-sterilisers": "UV Sterilisers",
  "shower-filters": "Shower Filters",
  "replacement-cartridges": "Replacement Cartridges",
  "filter-fittings": "Filter Fittings",
  "filter-taps": "Filter Taps",
  "filter-pumps": "Filter Pumps",
  "filter-tanks": "Filter Tanks",

  // bubblers-and-coolers/
  "commercial-bubblers": "Commercial Bubblers",
  "water-coolers": "Water Coolers",
  "taps-and-cartridges": "Taps & Cartridges",

  // more/
  "dosing-tanks": "Dosing Tanks",
  toilets: "Toilets",
  "bathroom-taps": "Bathroom Taps",
  "kitchen-taps": "Kitchen Taps",
  "vanities-and-basins": "Vanities & Basins",
  "bathroom-packages": "Bathroom Packages",
  "showers-and-fixtures": "Showers & Fixtures",
  "bathroom-accessories": "Bathroom Accessories",
};

// SKU prefix per NEW top-level — produces SKUs like EA-WF-4135.
// All 191 products in products.json have sku=null, so this is a clean
// re-keying — no preserved SKUs to honour. The previous migration used
// EA-{WF|DB|WP|CT|BA}-* for 5 top-levels; this restructure absorbs water-pumps
// into water-filters and merges drinking-bubblers/chemical-dosing-tanks/bathroom
// into the 3-tier scheme. Re-running the script regenerates SKUs against the
// new hierarchy: bubbler SKUs go from EA-DB-* → EA-BC-*, dosing/bathroom go
// EA-CT-*/EA-BA-* → EA-MR-*. Same clean-break logic as the previous step.
const SKU_PREFIX = {
  "water-filters": "EA-WF",
  "bubblers-and-coolers": "EA-BC",
  more: "EA-MR",
};

function deriveSku(primaryCategory, wpId) {
  const prefix = SKU_PREFIX[primaryCategory] ?? "EA-XX";
  return `${prefix}-${wpId}`;
}

// --- Three-tier remapping rules (2026-05) -----------------------------------
//
// The new structure collapses the previous 5 top-levels into 3:
//   water-filters         absorbs water-pumps + the under-sink-ro-systems split
//   bubblers-and-coolers  renames drinking-bubblers; bubbler-parts → taps-and-cartridges
//   more                  catch-all for chemical-dosing-tanks + bathroom
//
// Two rule-driven splits:
//   1. water-filters/under-sink-ro-systems (12 products) splits 3 ways by title.
//   2. water-filters/filter-fittings (33 products) is dissolved — products
//      redistribute to replacement-cartridges or filter-tanks by title rules.
//      The slug ceases to exist as a public category.
//
// Title rules use lowercase substring matching; ordering matters (more
// specific rules first).

const TANK_PHRASES = [
  "pressure switch",
  "pressure gauge",
  "pressure regulator",
  "pressure reducing",
  "pressure limiting",
  "ball valve",
  "shut off",
  "shut-off",
  "diverter valve",
  "flexible stainless",
  " hose ",
  "pvc hose",
  "pipe tube",
];

function remapCategory(p) {
  const main = p.main_collection;
  const sub = p.sub_collection;
  const title = String(p.title || "").toLowerCase();

  // Split rule for under-sink-ro-systems (12 products → bench-top / RO / under-sink).
  if (main === "water-filters" && sub === "under-sink-ro-systems") {
    if (title.includes("bench top") || title.includes("benchtop")) {
      return ["water-filters", "bench-top"];
    }
    if (
      title.includes(" ro ") ||
      title.includes("reverse osmosis") ||
      title.includes("desalination")
    ) {
      return ["water-filters", "reverse-osmosis"];
    }
    return ["water-filters", "under-sink"];
  }

  // Redistribution rule for filter-fittings (33 products → cartridges or tanks).
  if (main === "water-filters" && sub === "filter-fittings") {
    if (title.includes("membrane") || title.includes(" ro wrench")) {
      return ["water-filters", "replacement-cartridges"];
    }
    if (TANK_PHRASES.some((ph) => title.includes(ph))) {
      return ["water-filters", "filter-tanks"];
    }
    // Genuine fittings (push-fit elbows, locking clips, TDS testers, etc.)
    // land in replacement-cartridges via this fallback. Intentional per spec.
    return ["water-filters", "replacement-cartridges"];
  }

  // Direct moves within water-filters: rename whole-house-filters → whole-house.
  if (main === "water-filters") {
    if (sub === "whole-house-filters") return ["water-filters", "whole-house"];
    return ["water-filters", sub];
  }

  // water-pumps absorbs into water-filters as filter-pumps + filter-tanks.
  if (main === "water-pumps") {
    if (sub === "pressure-tanks") return ["water-filters", "filter-tanks"];
    // 12v-caravan-pumps + booster-pumps → filter-pumps
    return ["water-filters", "filter-pumps"];
  }

  // drinking-bubblers → bubblers-and-coolers (rename); bubbler-parts → taps-and-cartridges.
  if (main === "drinking-bubblers") {
    if (sub === "bubbler-parts") return ["bubblers-and-coolers", "taps-and-cartridges"];
    return ["bubblers-and-coolers", sub];
  }

  // chemical-dosing-tanks (1 product, no sub-cat) → more/dosing-tanks.
  if (main === "chemical-dosing-tanks") {
    return ["more", "dosing-tanks"];
  }

  // bathroom → more (preserves all sub-category slugs).
  if (main === "bathroom") {
    return ["more", sub];
  }

  // Unknown source — caller will error if this happens.
  return [null, null];
}

function priceBand(price) {
  if (price < 30) return "Under $30";
  if (price < 100) return "$30 – $100";
  if (price < 300) return "$100 – $300";
  if (price < 1000) return "$300 – $1,000";
  return "$1,000+";
}

function parseStages(raw) {
  if (raw == null) return undefined;
  const m = String(raw).match(/(\d+)/);
  return m ? Number(m[1]) : undefined;
}

function parseTechnology(raw) {
  if (!raw) return undefined;
  // filter_media may be comma- or +-separated. Trim whitespace, drop empties.
  const parts = String(raw)
    .split(/[,+]/)
    .map((s) => s.trim())
    .filter(Boolean);
  return parts.length > 0 ? parts : undefined;
}

function parseRemoves(raw) {
  if (!raw) return undefined;
  const parts = String(raw)
    .split(/,/)
    .map((s) => s.trim().toLowerCase())
    .filter(Boolean);
  return parts.length > 0 ? parts : undefined;
}

function parseCertifications(raw) {
  if (!raw) return [];
  return String(raw)
    .split(",")
    .map((s) => s.trim())
    .filter((s) => VALID_CERTIFICATIONS.has(s));
}

function parseFlowRate(raw) {
  if (raw == null) return undefined;
  // max_flow_lph values may be numeric or strings like "1500" or "1500 L/h".
  const m = String(raw).match(/(\d+(?:\.\d+)?)/);
  return m ? `${m[1]} LPH` : undefined;
}

function deriveApplication(productType, title) {
  const apps = [];
  if (productType === "bubbler" || productType === "water_cooler") {
    apps.push("commercial");
  }
  const lower = title.toLowerCase();
  if (lower.includes("bench top") || lower.includes("rental")) {
    apps.push("rental friendly");
  }
  return apps.length > 0 ? apps : undefined;
}

function deriveFacets(p, price) {
  const spec = p.specifications ?? {};
  const facets = {};

  const stages = parseStages(spec.filtration_stages);
  if (stages !== undefined) facets.stages = stages;

  if (spec.housing_size) facets.housing_size = String(spec.housing_size);
  if (spec.micron_rating) facets.micron = String(spec.micron_rating);

  const flow = parseFlowRate(spec.max_flow_lph);
  if (flow) facets.flow_rate = flow;

  const tech = parseTechnology(spec.filter_media);
  if (tech) facets.technology = tech;

  const removes = parseRemoves(spec.reduces);
  if (removes) facets.removes = removes;

  const application = deriveApplication(p.product_type, p.title);
  if (application) facets.application = application;

  // price_band is omitted for products without a real price — the band would
  // misleadingly read "Under $30" for a $0 placeholder.
  if (price > 0) facets.price_band = priceBand(price);

  return facets;
}

function deriveCategoryPath(mainCollection, subCollection) {
  const main = CATEGORY_TITLES[mainCollection] ?? mainCollection;
  if (!subCollection) return [main];
  const sub = CATEGORY_TITLES[subCollection] ?? subCollection;
  return [main, sub];
}

/**
 * Truncate to 200 chars at a word boundary, appending an ellipsis only when
 * the source string was actually trimmed. The catalogue's short_description
 * field averages ~250 chars; mid-word cuts look broken in card UI.
 */
function truncateShort(text) {
  if (!text) return "";
  if (text.length <= 200) return text;
  const slice = text.slice(0, 200);
  const lastSpace = slice.lastIndexOf(" ");
  const cut = lastSpace > 150 ? slice.slice(0, lastSpace) : slice;
  return `${cut.trimEnd()}…`;
}

function dedupe(arr) {
  return Array.from(new Set(arr));
}

function mapProduct(p) {
  const [primaryCategory, subCategory] = remapCategory(p);
  if (!primaryCategory) {
    throw new Error(
      `Unmapped product: ${p.handle} (main=${p.main_collection}, sub=${p.sub_collection})`
    );
  }

  const regularPrice = (p.price && p.price.regular) || 0;
  const salePrice = (p.price && p.price.sale) || null;
  const onSale = salePrice != null && salePrice < regularPrice;
  const displayPrice = onSale ? salePrice : regularPrice;

  // Stock: out_of_stock if Shopify says so OR if there's no real price (the
  // PDP buy box shows "Out of stock — call for ETA" which is the right UX
  // for unpriced products).
  const stockStatus = !p.in_stock || regularPrice <= 0 ? "out_of_stock" : "in_stock";

  return {
    id: String(p.old_wp_id),
    sku: p.sku || deriveSku(primaryCategory, p.old_wp_id),
    slug: p.handle,
    title: p.title,
    primaryCategory,
    subCategory,
    categoryPath: deriveCategoryPath(primaryCategory, subCategory),
    price: displayPrice,
    regularPrice,
    onSale,
    stockStatus,
    shortDescription: truncateShort(p.short_description ?? ""),
    longDescription: p.description ?? "",
    facets: deriveFacets(p, displayPrice),
    images: p.images ?? [],
    tags: dedupe(p.tags ?? []),
    certifications: parseCertifications(
      (p.specifications ?? {}).certifications
    ),
    kitHint: null,
    seoTitle: p.meta_title ?? p.title,
    seoDescription: p.meta_description ?? p.short_description ?? "",
  };
}

// --- TypeScript emission ----------------------------------------------------

/**
 * Emit a JS value as TypeScript-friendly source, double-quoted strings with
 * standard escapes and `\u00XX` for the few non-ASCII chars that the JSON
 * loader didn't already smooth over. Long descriptions go through a separate
 * template-literal path so authors can read the markdown unwrapped.
 */
function emitString(s) {
  return JSON.stringify(s);
}

function emitTemplate(s) {
  // Backticks need escaping; ${ does too (would interpolate).
  const escaped = s.replace(/\\/g, "\\\\").replace(/`/g, "\\`").replace(/\$\{/g, "\\${");
  return "`" + escaped + "`";
}

function emitFacets(facets) {
  const keys = Object.keys(facets);
  if (keys.length === 0) return "{}";
  const lines = keys.map((k) => {
    const v = facets[k];
    if (typeof v === "string") return `      ${JSON.stringify(k)}: ${emitString(v)},`;
    if (typeof v === "number") return `      ${JSON.stringify(k)}: ${v},`;
    if (Array.isArray(v))
      return `      ${JSON.stringify(k)}: [${v.map(emitString).join(", ")}],`;
    return `      ${JSON.stringify(k)}: ${JSON.stringify(v)},`;
  });
  return `{\n${lines.join("\n")}\n    }`;
}

function emitArray(arr, indent = "      ") {
  if (arr.length === 0) return "[]";
  const lines = arr.map((s) => `${indent}${emitString(s)},`);
  return `[\n${lines.join("\n")}\n    ]`;
}

function emitProduct(p) {
  return `  {
    id: ${emitString(p.id)},
    sku: ${emitString(p.sku)},
    slug: ${emitString(p.slug)},
    title: ${emitString(p.title)},
    primaryCategory: ${emitString(p.primaryCategory)},
    subCategory: ${emitString(p.subCategory)},
    categoryPath: [${p.categoryPath.map(emitString).join(", ")}],
    price: ${p.price},
    regularPrice: ${p.regularPrice},
    onSale: ${p.onSale},
    stockStatus: ${emitString(p.stockStatus)},
    shortDescription: ${emitString(p.shortDescription)},
    longDescription: ${emitTemplate(p.longDescription)},
    facets: ${emitFacets(p.facets)},
    images: ${emitArray(p.images)},
    tags: ${emitArray(p.tags)},
    certifications: [${p.certifications.map(emitString).join(", ")}],
    kitHint: ${p.kitHint == null ? "null" : emitString(p.kitHint)},
    seoTitle: ${emitString(p.seoTitle)},
    seoDescription: ${emitString(p.seoDescription)},
  },`;
}

function main() {
  const raw = fs.readFileSync(PRODUCTS_JSON, "utf8");
  const data = JSON.parse(raw);
  const products = data.products;

  if (!Array.isArray(products)) {
    throw new Error("products.json: expected an array under `products`");
  }

  // ---- Manual overrides --------------------------------------------------
  // data/category_overrides.json carries:
  //   - overrides:     WP_ID → [primaryCategory, subCategory] forced placement
  //   - drop:          WP_IDs to exclude from the public catalogue
  //   - needs_pricing: WP_IDs to render as out_of_stock until priced
  //   - duplicates:    pairs flagged for the merchant to review in Admin
  // The override file exists because the default rule-based mapping can't
  // resolve every edge case — particularly the dissolution of filter-fittings
  // and the redistribution of pumps/tanks across new sub-categories.
  const overridesRaw = fs.readFileSync(OVERRIDES_JSON, "utf8");
  const overridesData = JSON.parse(overridesRaw);
  const overrideMap = new Map();
  for (const [k, v] of Object.entries(overridesData.overrides)) {
    overrideMap.set(Number(k), v);
  }
  const dropSet = new Set(overridesData.drop ?? []);
  const needsPricingSet = new Set(overridesData.needs_pricing ?? []);
  const duplicatePairs = overridesData.duplicates ?? [];

  // Sanity-check the override file references real WP_IDs — typos here cause
  // silent no-ops that are extremely hard to debug later.
  const allWpIds = new Set(products.map((p) => p.old_wp_id));
  const orphanWarnings = [];
  for (const wp of overrideMap.keys()) {
    if (!allWpIds.has(wp)) orphanWarnings.push(`overrides: WP_ID ${wp} not found in products.json`);
  }
  for (const wp of dropSet) {
    if (!allWpIds.has(wp)) orphanWarnings.push(`drop: WP_ID ${wp} not found in products.json`);
  }
  for (const wp of needsPricingSet) {
    if (!allWpIds.has(wp)) orphanWarnings.push(`needs_pricing: WP_ID ${wp} not found in products.json`);
  }
  for (const warning of orphanWarnings) console.warn(`[overrides] ${warning}`);

  // Drop products before mapping — saves cycles and keeps the output clean.
  const kept = products.filter((p) => !dropSet.has(p.old_wp_id));

  const mapped = kept.map((p) => {
    const product = mapProduct(p);

    // Apply category override AFTER default mapping. The override defines the
    // final destination; we re-derive categoryPath and SKU prefix because the
    // primary may have changed (none currently do, but this stays robust).
    if (overrideMap.has(p.old_wp_id)) {
      const [main, sub] = overrideMap.get(p.old_wp_id);
      product.primaryCategory = main;
      product.subCategory = sub;
      product.categoryPath = deriveCategoryPath(main, sub);
      product.sku = p.sku || deriveSku(main, p.old_wp_id);
    }

    // needs_pricing → force out_of_stock so the buy box shows the unavailable
    // state instead of a $0 add-to-cart button. Stays out_of_stock until the
    // merchant sets a price in products.json (or in Shopify Admin once the
    // CSV is re-imported).
    if (needsPricingSet.has(p.old_wp_id)) {
      product.stockStatus = "out_of_stock";
    }

    return product;
  });

  // Sanity: warn if any flagged duplicate pair is missing the `duplicate_consolidation_needed`
  // marker in products.json. This mutation belongs in the source data, not in
  // the generated fixture — we just surface the gap so it can be patched.
  for (const [a, b] of duplicatePairs) {
    for (const wp of [a, b]) {
      const sourceProduct = products.find((p) => p.old_wp_id === wp);
      if (!sourceProduct) {
        console.warn(`[duplicates] WP_ID ${wp} not found in products.json`);
        continue;
      }
      const flagged = (sourceProduct.migration_notes || {}).duplicate_consolidation_needed === true;
      if (!flagged) {
        console.warn(
          `[duplicates] WP_ID ${wp} ("${(sourceProduct.title || "").slice(0, 60)}") missing migration_notes.duplicate_consolidation_needed in products.json`
        );
      }
    }
  }

  // Sanity reports — printed to stdout so they show up in CI logs and in the
  // terminal when re-running locally.
  const noPrice = mapped.filter((p) => p.regularPrice <= 0);
  const noCerts = mapped.filter((p) => p.certifications.length === 0);
  const handFinishedCount = products.filter(
    (p) => p.migration_notes && p.migration_notes.hand_finished
  ).length;
  const skuClashes = new Map();
  for (const p of mapped) {
    skuClashes.set(p.sku, (skuClashes.get(p.sku) ?? 0) + 1);
  }
  const dupeSkus = [...skuClashes.entries()].filter(([, n]) => n > 1);
  if (dupeSkus.length > 0) {
    throw new Error(
      `Duplicate SKUs after derivation — investigate before importing:\n` +
        dupeSkus.map(([sku, n]) => `  ${sku}: ${n}×`).join("\n")
    );
  }

  const slugClashes = new Map();
  for (const p of mapped) {
    slugClashes.set(p.slug, (slugClashes.get(p.slug) ?? 0) + 1);
  }
  const dupeSlugs = [...slugClashes.entries()].filter(([, n]) => n > 1);
  if (dupeSlugs.length > 0) {
    throw new Error(
      `Duplicate slugs (handles) after migration — Shopify will reject the import:\n` +
        dupeSlugs.map(([slug, n]) => `  ${slug}: ${n}×`).join("\n")
    );
  }

  const header = `/**
 * Product catalogue fixture — generated from products.json by
 * scripts/migrate-catalogue.mjs.
 *
 * DO NOT HAND-EDIT THIS FILE. Re-run the migration script:
 *     node scripts/migrate-catalogue.mjs
 *
 * Editorial content (titles, copy, images, facets, SEO) is the source of
 * truth here. Live price and stock are merged in at render time by
 * lib/shopify/product-state.ts — this fixture is the fallback when
 * Shopify is unavailable.
 *
 * Generated: ${new Date().toISOString()}
 * Products:  ${mapped.length}
 */

import type { Product } from "@/types/product";

export const PRODUCTS: Product[] = [
${mapped.map(emitProduct).join("\n")}
];
`;

  fs.writeFileSync(OUTPUT_PATH, header, "utf8");

  console.log(`Wrote ${OUTPUT_PATH}`);
  console.log(`  Products:        ${mapped.length}`);
  console.log(`  Hand-finished:   ${handFinishedCount}`);
  console.log(`  Missing price:   ${noPrice.length}  (marked out_of_stock)`);
  console.log(`  Missing certs:   ${noCerts.length}`);

  // Distribution table — printed in canonical render order so the output is
  // greppable against the spec's expected counts. The third column is the
  // expected count for the current state of products.json + the override
  // file; mismatches don't throw (data may legitimately drift) but they
  // surface loudly with " <-- MISMATCH" so we never ship a quiet regression.
  const RENDER_ORDER = [
    ["water-filters", "whole-house", 14],
    ["water-filters", "under-sink", 2],
    ["water-filters", "reverse-osmosis", 9],
    ["water-filters", "bench-top", 3],
    ["water-filters", "uv-sterilisers", 10],
    ["water-filters", "shower-filters", 1],
    ["water-filters", "replacement-cartridges", 38],
    ["water-filters", "filter-fittings", 31],
    ["water-filters", "filter-taps", 9],
    ["water-filters", "filter-pumps", 5],
    ["water-filters", "filter-tanks", 12],
    ["bubblers-and-coolers", "commercial-bubblers", 3],
    ["bubblers-and-coolers", "water-coolers", 4],
    ["bubblers-and-coolers", "taps-and-cartridges", 2],
    ["more", "dosing-tanks", 1],
    ["more", "toilets", 8],
    ["more", "bathroom-taps", 5],
    ["more", "kitchen-taps", 5],
    ["more", "vanities-and-basins", 6],
    ["more", "bathroom-packages", 12],
    ["more", "showers-and-fixtures", 2],
    ["more", "bathroom-accessories", 5],
  ];
  const counts = new Map();
  for (const p of mapped) {
    const key = `${p.primaryCategory}/${p.subCategory}`;
    counts.set(key, (counts.get(key) ?? 0) + 1);
  }

  console.log("\nDistribution by (primaryCategory / subCategory):");
  let runningTotal = 0;
  let mismatches = 0;
  let lastTop = "";
  for (const [main, sub, expected] of RENDER_ORDER) {
    if (main !== lastTop) {
      console.log(`  ${main}/`);
      lastTop = main;
    }
    const n = counts.get(`${main}/${sub}`) ?? 0;
    runningTotal += n;
    let flag = "";
    if (n === 0) flag = "  <-- EMPTY";
    else if (n !== expected) {
      flag = `  <-- MISMATCH (expected ${expected})`;
      mismatches++;
    }
    console.log(
      `    ${sub.padEnd(24)} ${String(n).padStart(3)}  (exp ${String(expected).padStart(3)})${flag}`
    );
  }
  console.log(`  ─────────────────────────────`);
  console.log(`  Total: ${runningTotal}  (dropped: ${dropSet.size}, needs_pricing: ${needsPricingSet.size})`);

  if (runningTotal !== mapped.length) {
    throw new Error(
      `Distribution total ${runningTotal} ≠ products ${mapped.length}. A product landed outside the canonical render order — fix remapCategory.`
    );
  }
  for (const [main, sub] of RENDER_ORDER) {
    if ((counts.get(`${main}/${sub}`) ?? 0) === 0) {
      throw new Error(
        `Sub-category "${main}/${sub}" has zero products. Either the rule is missing a case or the slug is wrong.`
      );
    }
  }
  if (mismatches > 0) {
    console.warn(
      `\n[counts] ${mismatches} sub-category count(s) drifted from spec. Investigate before opening the PR.`
    );
  }
}

